        .or_else(|| {
            js_sys::global()
                .dyn_into::<web_sys::WorkerGlobalScope>()
                .ok()
                .and_then(|w| w.performance())
        });
    if let Some(perf) = perf {
        let now = perf.now();
        let _ = cell.set(perf);
        now
    } else {
        js_sys::Date::now()
    }
